1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { items: Item[] };
14	type Scenario = { steps: Step[] };
15	
16	const basePremiumForItems = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
18	
19	const quotePremium = (items: Item[]): number => {
20	  const basePremium = basePremiumForItems(items);
21	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
22	  return Math.ceil(basePremium + firstInsuranceSurcharge) + PROCESSING_FEE;
23	};
24	
25	export const runScenario = (scenario: Scenario): unknown => {
26	  const results = scenario.steps.map((step) => ({
27	    premium: quotePremium(step.items),
28	  }));
29	  return { results };
30	};
